// Linear Search: With comparison counting
// Input: Array A[0..n-1], key to search
// Output: Index if found, -1 otherwise; comparisons via reference

FUNCTION LinearSearch(A, n, key, REF comparisons):
    comparisons ← 0

    FOR i FROM 0 TO n-1 DO:
        comparisons ← comparisons + 1
        IF A[i] = key THEN:
            RETURN i        // Found at index i
        END IF
    END FOR

    RETURN -1               // Not found
END FUNCTION

// Analysis:
// Best Case: key at index 0 → 1 comparison → O(1)
// Average Case: key uniformly distributed → (n+1)/2 comparisons → O(n)
// Worst Case: key at index n-1 or absent → n comparisons → O(n)
